BPNN *bpnn_internal_create(int n_in, int n_hidden, int n_out)
{
  BPNN *newnet;

  newnet = (BPNN *) malloc (sizeof (BPNN));
  if (newnet == NULL) {
    printf("BPNN_CREATE: Couldn't allocate neural network\n");
    return (NULL);
  }

  newnet->input_n = n_in;
  newnet->hidden_n = n_hidden;
  newnet->output_n = n_out;
  newnet->input_units = alloc_1d_dbl(n_in + 1);
  newnet->hidden_units = alloc_1d_dbl(n_hidden + 1);
  newnet->output_units = alloc_1d_dbl(n_out + 1);

  newnet->hidden_delta = alloc_1d_dbl(n_hidden + 1);
  newnet->output_delta = alloc_1d_dbl(n_out + 1);
  newnet->target = alloc_1d_dbl(n_out + 1);

  newnet->input_weights = alloc_2d_dbl(n_in + 1, n_hidden + 1);
  newnet->hidden_weights = alloc_2d_dbl(n_hidden + 1, n_out + 1);

  newnet->input_prev_weights = alloc_2d_dbl(n_in + 1, n_hidden + 1);
  newnet->hidden_prev_weights = alloc_2d_dbl(n_hidden + 1, n_out + 1);

  return (newnet);
}

void bpnn_free(BPNN *net)
{
  int n1, n2, i;

  n1 = net->input_n;
  n2 = net->hidden_n;

  free((char *) net->input_units);
  free((char *) net->hidden_units);
  free((char *) net->output_units);

  free((char *) net->hidden_delta);
  free((char *) net->output_delta);
  free((char *) net->target);

  for (i = 0; i <= n1; i++) {
    free((char *) net->input_weights[i]);
    free((char *) net->input_prev_weights[i]);
  }
  free((char *) net->input_weights);
  free((char *) net->input_prev_weights);

  for (i = 0; i <= n2; i++) {
    free((char *) net->hidden_weights[i]);
    free((char *) net->hidden_prev_weights[i]);
  }
  free((char *) net->hidden_weights);
  free((char *) net->hidden_prev_weights);

  free((char *) net);
}

BPNN *bpnn_create(int n_in, int n_hidden, int n_out)
{
  BPNN *newnet;

  newnet = bpnn_internal_create(n_in, n_hidden, n_out);

#ifdef INITZERO
  bpnn_zero_weights(newnet->input_weights, n_in, n_hidden);
#else
  bpnn_randomize_weights(newnet->input_weights, n_in, n_hidden);
#endif
  bpnn_randomize_weights(newnet->hidden_weights, n_hidden, n_out);
  bpnn_zero_weights(newnet->input_prev_weights, n_in, n_hidden);
  bpnn_zero_weights(newnet->hidden_prev_weights, n_hidden, n_out);
  bpnn_randomize_row(newnet->target, n_out);
  return (newnet);
}

__global__ void bpnn_layerforward_kernel(float *l1, float *l2, float *conn, int n1, int n2)
{
  int j = blockIdx.x * blockDim.x + threadIdx.x + 1;
  if (j <= n2) {
    float sum = 0.0f;
    for (int k = 0; k <= n1; k++) {
      sum += conn[k*(n2+1) + j] * l1[k];
    }
    l2[j] = 1.0f / (1.0f + expf(-sum));
  }
}

void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2)
{
  l1[0] = 1.0f;

  int size_conn = (n1+1)*(n2+1);
  float *conn_flat = (float *)malloc(size_conn * sizeof(float));
  for (int i = 0; i <= n1; i++) {
    for (int j = 0; j <= n2; j++) {
      conn_flat[i*(n2+1) + j] = conn[i][j];
    }
  }

  float *d_l1, *d_l2, *d_conn;
  cudaMalloc((void**)&d_l1, (n1+1)*sizeof(float));
  cudaMalloc((void**)&d_l2, (n2+1)*sizeof(float));
  cudaMalloc((void**)&d_conn, size_conn*sizeof(float));

  cudaMemcpy(d_l1, l1, (n1+1)*sizeof(float), cudaMemcpyHostToDevice);
  cudaMemcpy(d_conn, conn_flat, size_conn*sizeof(float), cudaMemcpyHostToDevice);

  int threadsPerBlock = 256;
  int blocksPerGrid = (n2 + threadsPerBlock - 1) / threadsPerBlock;

  bpnn_layerforward_kernel<<<blocksPerGrid, threadsPerBlock>>>(d_l1, d_l2, d_conn, n1, n2);
  cudaDeviceSynchronize();

  cudaMemcpy(l2, d_l2, (n2+1)*sizeof(float), cudaMemcpyDeviceToHost);

  cudaFree(d_l1);
  cudaFree(d_l2);
  cudaFree(d_conn);
  free(conn_flat);
}

void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err)
{
  int j;
  float o, t, errsum;
  errsum = 0.0f;
  for (j = 1; j <= nj; j++) {
    o = output[j];
    t = target[j];
    delta[j] = o * (1.0f - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err)
{
  int j, k;
  float h, sum, errsum;

  errsum = 0.0f;
  for (j = 1; j <= nh; j++) {
    h = hidden[j];
    sum = 0.0f;
    for (k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0f - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

__global__ void bpnn_adjust_weights_kernel(float *delta, int ndelta, float *ly, int nly, float *w, float *oldw)
{
  int j = blockIdx.x * blockDim.x + threadIdx.x + 1;
  if (j <= ndelta) {
    for (int k = 0; k <= nly; k++) {
      float new_dw = (ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k*(ndelta+1) + j]);
      w[k*(ndelta+1) + j] += new_dw;
      oldw[k*(ndelta+1) + j] = new_dw;
    }
  }
}

void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw)
{
  ly[0] = 1.0f;

  int size_w = (nly+1)*(ndelta+1);
  float *w_flat = (float *)malloc(size_w * sizeof(float));
  float *oldw_flat = (float *)malloc(size_w * sizeof(float));
  for (int i = 0; i <= nly; i++) {
    for (int j = 0; j <= ndelta; j++) {
      w_flat[i*(ndelta+1) + j] = w[i][j];
      oldw_flat[i*(ndelta+1) + j] = oldw[i][j];
    }
  }

  float *d_delta, *d_ly, *d_w, *d_oldw;
  cudaMalloc((void**)&d_delta, (ndelta+1)*sizeof(float));
  cudaMalloc((void**)&d_ly, (nly+1)*sizeof(float));
  cudaMalloc((void**)&d_w, size_w*sizeof(float));
  cudaMalloc((void**)&d_oldw, size_w*sizeof(float));

  cudaMemcpy(d_delta, delta, (ndelta+1)*sizeof(float), cudaMemcpyHostToDevice);
  cudaMemcpy(d_ly, ly, (nly+1)*sizeof(float), cudaMemcpyHostToDevice);
  cudaMemcpy(d_w, w_flat, size_w*sizeof(float), cudaMemcpyHostToDevice);
  cudaMemcpy(d_oldw, oldw_flat, size_w*sizeof(float), cudaMemcpyHostToDevice);

  int threadsPerBlock = 256;
  int blocksPerGrid = (ndelta + threadsPerBlock - 1) / threadsPerBlock;

  bpnn_adjust_weights_kernel<<<blocksPerGrid, threadsPerBlock>>>(d_delta, ndelta, d_ly, nly, d_w, d_oldw);
  cudaDeviceSynchronize();

  cudaMemcpy(w_flat, d_w, size_w*sizeof(float), cudaMemcpyDeviceToHost);
  cudaMemcpy(oldw_flat, d_oldw, size_w*sizeof(float), cudaMemcpyDeviceToHost);

  for (int i = 0; i <= nly; i++) {
    for (int j = 0; j <= ndelta; j++) {
      w[i][j] = w_flat[i*(ndelta+1) + j];
      oldw[i][j] = oldw_flat[i*(ndelta+1) + j];
    }
  }

  cudaFree(d_delta);
  cudaFree(d_ly);
  cudaFree(d_w);
  cudaFree(d_oldw);
  free(w_flat);
  free(oldw_flat);
}

void bpnn_feedforward(BPNN *net)
{
  int in = net->input_n;
  int hid = net->hidden_n;
  int out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
}

void bpnn_train(BPNN *net, float *eo, float *eh)
{
  int in = net->input_n;
  int hid = net->hidden_n;
  int out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);

  bpnn_output_error(net->output_delta, net->target, net->output_units, out, eo);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, eh);

  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);
  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in, net->input_weights, net->input_prev_weights);
}

void bpnn_save(BPNN *net, char *filename)
{
  int n1, n2, n3, i, j, memcnt;
  float dvalue, **w;
  char *mem;

  FILE *pFile;
  pFile = fopen(filename, "w+");

  n1 = net->input_n;  n2 = net->hidden_n;  n3 = net->output_n;
  printf("Saving %dx%dx%d network to '%s'\n", n1, n2, n3, filename);

  fwrite((char *) &n1 , sizeof(char), sizeof(char), pFile);
  fwrite((char *) &n2 , sizeof(char), sizeof(char), pFile);
  fwrite((char *) &n3 , sizeof(char), sizeof(char), pFile);

  memcnt = 0;
  w = net->input_weights;
  mem = (char *) malloc ((unsigned) ((n1+1) * (n2+1) * sizeof(float)));
  for (i = 0; i <= n1; i++) {
    for (j = 0; j <= n2; j++) {
      dvalue = w[i][j];
      fastcopy(&mem[memcnt], &dvalue, sizeof(float));
      memcnt += sizeof(float);
    }
  }

  fwrite(mem, (unsigned)(sizeof(float)), (unsigned) ((n1+1) * (n2+1) * sizeof(float)), pFile);
  free(mem);

  memcnt = 0;
  w = net->hidden_weights;
  mem = (char *) malloc ((unsigned) ((n2+1) * (n3+1) * sizeof(float)));
  for (i = 0; i <= n2; i++) {
    for (j = 0; j <= n3; j++) {
      dvalue = w[i][j];
      fastcopy(&mem[memcnt], &dvalue, sizeof(float));
      memcnt += sizeof(float);
    }
  }

  fwrite(mem, sizeof(float), (unsigned) ((n2+1) * (n3+1) * sizeof(float)), pFile);
  free(mem);

  fclose(pFile);
  return;
}

BPNN *bpnn_read(char *filename)
{
  char *mem;
  BPNN *new;
  int fd, n1, n2, n3, i, j, memcnt;

  if ((fd = open(filename, O_RDONLY, 0644)) == -1) {
    return (NULL);
  }

  printf("Reading '%s'\n", filename);

  read(fd, (char *) &n1, sizeof(int));
  read(fd, (char *) &n2, sizeof(int));
  read(fd, (char *) &n3, sizeof(int));
  new = bpnn_internal_create(n1, n2, n3);

  printf("'%s' contains a %dx%dx%d network\n", filename, n1, n2, n3);
  printf("Reading input weights...");

  memcnt = 0;
  mem = (char *) malloc ((unsigned) ((n1+1) * (n2+1) * sizeof(float)));
  read(fd, mem, (n1+1) * (n2+1) * sizeof(float));
  for (i = 0; i <= n1; i++) {
    for (j = 0; j <= n2; j++) {
      fastcopy(&(new->input_weights[i][j]), &mem[memcnt], sizeof(float));
      memcnt += sizeof(float);
    }
  }
  free(mem);

  printf("Done\nReading hidden weights...");

  memcnt = 0;
  mem = (char *) malloc ((unsigned) ((n2+1) * (n3+1) * sizeof(float)));
  read(fd, mem, (n2+1) * (n3+1) * sizeof(float));
  for (i = 0; i <= n2; i++) {
    for (j = 0; j <= n3; j++) {
      fastcopy(&(new->hidden_weights[i][j]), &mem[memcnt], sizeof(float));
      memcnt += sizeof(float);
    }
  }
  free(mem);
  close(fd);

  printf("Done\n");

  bpnn_zero_weights(new->input_prev_weights, n1, n2);
  bpnn_zero_weights(new->hidden_prev_weights, n2, n3);

  return (new);
}

